document.documentElement.classList.add('loading');
if ('scrollRestoration' in history) history.scrollRestoration = 'manual';

const pageLoader = document.getElementById('page-loader');
let loaderHidden = false;

function forceTop(){
  window.scrollTo(0, 0);
  document.documentElement.scrollTop = 0;
  document.body.scrollTop = 0;
}

function hidePageLoader(){
  if(loaderHidden) return;
  loaderHidden = true;
  forceTop();
  document.documentElement.classList.remove('loading');
  if(pageLoader){
    pageLoader.classList.add('hidden');
    setTimeout(() => pageLoader.remove(), 520);
  }
}

forceTop();
window.addEventListener('beforeunload', forceTop);
window.addEventListener('pageshow', forceTop);
window.addEventListener('load', () => {
  forceTop();
  setTimeout(hidePageLoader, 220);
});
setTimeout(hidePageLoader, 2200);

const cur=document.getElementById('cur'),curR=document.getElementById('cur-r');
document.addEventListener('mousemove',e=>{
  cur.style.left=e.clientX+'px';cur.style.top=e.clientY+'px';
  curR.style.left=e.clientX+'px';curR.style.top=e.clientY+'px';
});
document.querySelectorAll('a,button,.rank-btn,.opt-btn,.addon-item,.faq-q,.pay-method,.contact-card').forEach(el=>{
  el.addEventListener('mouseenter',()=>{curR.style.width='50px';curR.style.height='50px';curR.style.borderColor='var(--cyan)';});
  el.addEventListener('mouseleave',()=>{curR.style.width='32px';curR.style.height='32px';curR.style.borderColor='var(--glow)';});
});

const bgC=document.getElementById('bg');
const renderer=new THREE.WebGLRenderer({canvas:bgC,antialias:true});
renderer.setPixelRatio(Math.min(window.devicePixelRatio,2));
renderer.setSize(window.innerWidth,window.innerHeight);
renderer.setClearColor(0x050008,1);
const scene=new THREE.Scene();
const camera=new THREE.PerspectiveCamera(75,window.innerWidth/window.innerHeight,.1,3000);
camera.position.set(0,0,1);
function mkS(n,sp,sz,col,z){const g=new THREE.BufferGeometry(),p=new Float32Array(n*3),c=new Float32Array(n*3),s=new Float32Array(n);const cl=new THREE.Color(col);for(let i=0;i<n;i++){p[i*3]=(Math.random()-.5)*sp;p[i*3+1]=(Math.random()-.5)*sp*.6;p[i*3+2]=z+(Math.random()-.5)*200;const b=.4+Math.random()*.6;c[i*3]=cl.r*b;c[i*3+1]=cl.g*b;c[i*3+2]=cl.b*b;s[i]=sz*(.5+Math.random());}g.setAttribute('position',new THREE.BufferAttribute(p,3));g.setAttribute('color',new THREE.BufferAttribute(c,3));g.setAttribute('size',new THREE.BufferAttribute(s,1));return new THREE.Points(g,new THREE.ShaderMaterial({vertexColors:true,transparent:true,blending:THREE.AdditiveBlending,depthWrite:false,vertexShader:`attribute float size;varying vec3 vColor;void main(){vColor=color;vec4 mv=modelViewMatrix*vec4(position,1.);gl_PointSize=size*(300./-mv.z);gl_Position=projectionMatrix*mv;}`,fragmentShader:`varying vec3 vColor;void main(){float d=distance(gl_PointCoord,vec2(.5));if(d>.5)discard;float a=1.-smoothstep(.2,.5,d);gl_FragColor=vec4(vColor,a);}`}));}
scene.add(mkS(4500,2400,1.2,0xffffff,-500));scene.add(mkS(1600,1700,2.,0xAA66FF,-300));scene.add(mkS(550,950,2.8,0x66DDFF,-100));scene.add(mkS(320,1200,1.8,0xFF88CC,-420));scene.add(mkS(180,900,3.2,0xFFDD88,-260));
function mkN(n,sp,col,op,z){const g=new THREE.BufferGeometry(),p=new Float32Array(n*3);for(let i=0;i<n;i++){const t=Math.random()*Math.PI*2,r=Math.random()*sp;p[i*3]=Math.cos(t)*r;p[i*3+1]=(Math.random()-.5)*sp*.3;p[i*3+2]=z;}g.setAttribute('position',new THREE.BufferAttribute(p,3));return new THREE.Points(g,new THREE.PointsMaterial({color:col,size:22,transparent:true,opacity:op,blending:THREE.AdditiveBlending,depthWrite:false,sizeAttenuation:true}));}
const n1=mkN(900,750,0x661AA3,.05,-620),n2=mkN(500,550,0x220033,.07,-720),n3=mkN(400,480,0x001133,.05,-670);
scene.add(n1,n2,n3);
const shots=[];let frame=0;
function spawnShot(){const g=new THREE.BufferGeometry();const len=45+Math.random()*85,x=(Math.random()-.5)*1500,y=(Math.random()-.5)*750,z2=-300;const ang=-Math.PI/6+(Math.random()-.5)*.55;const v=new Float32Array([x,y,z2,x-Math.cos(ang)*len,y-Math.sin(ang)*len,z2]);g.setAttribute('position',new THREE.BufferAttribute(v,3));const mat=new THREE.LineBasicMaterial({color:0xCCAAFF,transparent:true,opacity:.9,blending:THREE.AdditiveBlending});const line=new THREE.Line(g,mat);scene.add(line);shots.push({line,dx:Math.cos(ang)*(12+Math.random()*15),dy:Math.sin(ang)*(12+Math.random()*15),life:0,max:50+Math.random()*40,mat});}
let tx=0,ty=0,cx2=0,cy2=0;
document.addEventListener('mousemove',e=>{tx=(e.clientX/window.innerWidth-.5)*2;ty=(e.clientY/window.innerHeight-.5)*2;});
document.addEventListener('touchmove',e=>{tx=(e.touches[0].clientX/window.innerWidth-.5)*2;ty=(e.touches[0].clientY/window.innerHeight-.5)*2;},{passive:true});
(function loop(){requestAnimationFrame(loop);frame++;cx2+=(tx-cx2)*.028;cy2+=(ty-cy2)*.028;camera.position.x=cx2*65;camera.position.y=-cy2*32;camera.lookAt(cx2*22,-cy2*11,-200);n1.rotation.z+=.00028;n2.rotation.z-=.00018;n3.rotation.z+=.00012;if(frame%75===0)spawnShot();for(let i=shots.length-1;i>=0;i--){const s=shots[i];s.life++;const p=s.line.geometry.attributes.position.array;p[0]+=s.dx;p[1]+=s.dy;p[3]+=s.dx;p[4]+=s.dy;s.line.geometry.attributes.position.needsUpdate=true;const pg=s.life/s.max;s.mat.opacity=pg<.2?pg*5:Math.max(0,(1-pg)*1.2);if(s.life>=s.max){scene.remove(s.line);shots.splice(i,1);}}renderer.render(scene,camera);})();
window.addEventListener('resize',()=>{camera.aspect=window.innerWidth/window.innerHeight;camera.updateProjectionMatrix();renderer.setSize(window.innerWidth,window.innerHeight);});

