function imgSrcByTierKey(key){ return RANK_ICON_MAP[key] || RANK_ICON_MAP.bronze; }
function imgSrc(id){
  const tier = RANK_TIERS.find(t => t.ranks.some(r => r.id === id));
  return tier ? imgSrcByTierKey(tier.key) : RANK_ICON_MAP.bronze;
}

const rankState = {
  from: { tier: 0, division: 0 },
  to: { tier: 2, division: 0 },
};

let queueMult=1, addonMult=1;

function getRank(side){
  const sideState = rankState[side];
  return RANK_TIERS[sideState.tier].ranks[sideState.division] || RANK_TIERS[sideState.tier].ranks[0];
}

function getTier(side){
  return RANK_TIERS[rankState[side].tier];
}

function setTier(side, tierIndex){
  rankState[side].tier = tierIndex;
  const ranks = RANK_TIERS[tierIndex].ranks;
  rankState[side].division = Math.min(rankState[side].division, ranks.length - 1);
  renderRankPicker(side);
  updateDisplay();
}

function setDivision(side, divisionIndex){
  rankState[side].division = divisionIndex;
  renderDivisionButtons(side);
  updateDisplay();
}

function renderTierButtons(side){
  const container = document.getElementById(`${side}-tier-grid`);
  container.innerHTML = '';
  RANK_TIERS.forEach((tier, tierIndex) => {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'rank-icon-btn' + (rankState[side].tier === tierIndex ? ' active' : '');
    btn.title = tier.label;
    btn.setAttribute('aria-label', tier.label);
    btn.innerHTML = `<img src="${tier.icon}" alt="${tier.label}"><span class="rank-label">${tier.label}</span>`;
    btn.addEventListener('click', () => setTier(side, tierIndex));
    container.appendChild(btn);
    if(rankState[side].tier === tierIndex){
      requestAnimationFrame(() => btn.scrollIntoView({block:'nearest', behavior:'smooth'}));
    }
  });
}

function renderDivisionButtons(side){
  const container = document.getElementById(`${side}-division-row`);
  const tier = getTier(side);
  container.className = 'rank-division-row' + (tier.ranks.length === 1 ? ' single' : '');
  container.innerHTML = '';
  tier.ranks.forEach((rank, divisionIndex) => {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'rank-division-btn' + (rankState[side].division === divisionIndex ? ' active' : '');
    btn.textContent = rank.division;
    btn.addEventListener('click', () => setDivision(side, divisionIndex));
    container.appendChild(btn);
  });
}

function renderRankPicker(side){
  renderTierButtons(side);
  renderDivisionButtons(side);
}

function updateDisplay(){
  const fr = getRank('from');
  const tr = getRank('to');
  const fromTier = getTier('from');
  const toTier = getTier('to');

  document.getElementById('from-img').src  = imgSrc(fr.id);
  document.getElementById('from-name').textContent = fr.name;
  document.getElementById('to-img').src    = imgSrc(tr.id);
  document.getElementById('to-name').textContent = tr.name;
  document.getElementById('from-name').classList.toggle('ssl', fromTier.key === 'ssl');
  document.getElementById('to-name').classList.toggle('ssl', toTier.key === 'ssl');

  document.getElementById('sum-from-img').src = imgSrc(fr.id);
  document.getElementById('sum-from-n').textContent = fr.name;
  document.getElementById('sum-to-img').src   = imgSrc(tr.id);
  document.getElementById('sum-to-n').textContent = tr.name;

  const diff = Math.max(0, tr.flat - fr.flat);
  const BASE_PRICE_BY_RANK = [
    0.00, 2.50, 3.75,
    5.00, 8.48, 11.97,
    15.45, 18.71, 21.96,
    25.22, 32.37, 39.52,
    46.67, 59.77, 72.86,
    85.96, 120.04, 154.11, 188.19,
    217.85, 247.51, 277.17
  ];
  const fromIndex = fr.flat;
  const toIndex = tr.flat;
  let base = 0;
  if (toIndex > fromIndex) base = BASE_PRICE_BY_RANK[toIndex] - BASE_PRICE_BY_RANK[fromIndex];
  base = base * 0.70 * queueMult * addonMult;
  document.getElementById('sum-price').textContent = '$' + base.toFixed(2);
  document.getElementById('sum-old').textContent   = '$' + (base / 0.70).toFixed(2);
  const days = diff===0?'—':diff<=2?'< 1 día':diff<=6?'1-2 días':diff<=12?'2-4 días':diff<=18?'4-6 días':'6-8 días';
  document.getElementById('sum-time').textContent  = days;
}

renderRankPicker('from');
renderRankPicker('to');
updateDisplay();

document.querySelectorAll('#queue-opts .opt-btn').forEach(btn=>{
  btn.addEventListener('click',()=>{
    document.querySelectorAll('#queue-opts .opt-btn').forEach(b=>b.classList.remove('active'));
    btn.classList.add('active');
    queueMult=parseFloat(btn.dataset.mult);
    document.getElementById('sum-queue').textContent=btn.dataset.queue;
    updateDisplay();
  });
});
document.querySelectorAll('#platform-opts .opt-btn').forEach(btn=>{
  btn.addEventListener('click',()=>{
    document.querySelectorAll('#platform-opts .opt-btn').forEach(b=>b.classList.remove('active'));
    btn.classList.add('active');
    document.getElementById('sum-plat').textContent=btn.dataset.plat;
  });
});
document.querySelectorAll('.addon-item').forEach(item=>{
  item.addEventListener('click',()=>{
    item.classList.toggle('active');
    let extra=0;
    document.querySelectorAll('.addon-item.active').forEach(a=>extra+=parseFloat(a.dataset.cost));
    addonMult=1+extra;
    const names=[];
    document.querySelectorAll('.addon-item.active').forEach(a=>{
      names.push(a.querySelector('.addon-label').textContent.replace(/[🔒👤🎥⚡🛡️💎]/g,'').trim());
    });
    document.getElementById('sum-addons').textContent=names.length?names.join(', '):'Ninguno';
    updateDisplay();
  });
});
document.querySelectorAll('.faq-q').forEach(q=>{
  q.addEventListener('click',()=>{
    const item=q.parentElement,was=item.classList.contains('open');
    document.querySelectorAll('.faq-item').forEach(i=>i.classList.remove('open'));
    if(!was)item.classList.add('open');
  });
});
